# nginx.conf — least-connections load balancing across 2 vLLM replicas
upstream vllm_backend {
    least_conn;                         # route to least-busy upstream
    server vllm-0.vllm:8000;
    server vllm-1.vllm:8000;
    keepalive 64;                       # reuse HTTP connections
}

server {
    listen 80;

    # Disable response buffering for SSE streaming
    proxy_buffering off;
    proxy_cache off;

    # Long timeouts for streaming responses
    proxy_read_timeout 600s;
    proxy_send_timeout 600s;

    location /v1/ {
        proxy_pass http://vllm_backend;
        proxy_set_header Connection "";    # HTTP/1.1 keep-alive
        proxy_http_version 1.1;
    }

    location /health {
        proxy_pass http://vllm_backend;
    }
}
